import{_ as t,c as r,o as a,a2 as o}from"./chunks/framework.C9oX9vvB.js";const g=JSON.parse('{"title":"Acknowledgments 🏆","description":"","frontmatter":{},"headers":[],"relativePath":"acknowledgments.md","filePath":"acknowledgments.md"}'),n={name:"acknowledgments.md"};function i(l,e,s,d,u,h){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="acknowledgments-🏆" tabindex="-1">Acknowledgments 🏆 <a class="header-anchor" href="#acknowledgments-🏆" aria-label="Permalink to &quot;Acknowledgments 🏆&quot;">​</a></h1><p>Duck-UI wouldn&#39;t be possible without the amazing open-source community and the incredible tools built by talented developers worldwide.</p><h2 id="core-technologies" tabindex="-1">Core Technologies <a class="header-anchor" href="#core-technologies" aria-label="Permalink to &quot;Core Technologies&quot;">​</a></h2><h3 id="duckdb" tabindex="-1">DuckDB <a class="header-anchor" href="#duckdb" aria-label="Permalink to &quot;DuckDB&quot;">​</a></h3><p>A huge thank you to the <a href="https://duckdb.org/" target="_blank" rel="noreferrer">DuckDB</a> team for creating this incredible analytical database system and making it available as WebAssembly. DuckDB&#39;s performance, SQL compatibility, and developer-friendly approach make it a joy to work with.</p><ul><li><strong>Website</strong>: <a href="https://duckdb.org/" target="_blank" rel="noreferrer">duckdb.org</a></li><li><strong>GitHub</strong>: <a href="https://github.com/duckdb/duckdb" target="_blank" rel="noreferrer">github.com/duckdb/duckdb</a></li><li><strong>WASM</strong>: <a href="https://github.com/duckdb/duckdb-wasm" target="_blank" rel="noreferrer">github.com/duckdb/duckdb-wasm</a></li></ul><h2 id="key-dependencies" tabindex="-1">Key Dependencies <a class="header-anchor" href="#key-dependencies" aria-label="Permalink to &quot;Key Dependencies&quot;">​</a></h2><h3 id="ui-framework-libraries" tabindex="-1">UI Framework &amp; Libraries <a class="header-anchor" href="#ui-framework-libraries" aria-label="Permalink to &quot;UI Framework &amp; Libraries&quot;">​</a></h3><ul><li><strong><a href="https://reactjs.org/" target="_blank" rel="noreferrer">React</a></strong> - The foundation of our user interface</li><li><strong><a href="https://tailwindcss.com/" target="_blank" rel="noreferrer">Tailwind CSS</a></strong> - Beautiful, utility-first styling</li><li><strong><a href="https://www.radix-ui.com/" target="_blank" rel="noreferrer">Radix UI</a></strong> - Accessible, unstyled component primitives</li><li><strong><a href="https://ui.shadcn.com/" target="_blank" rel="noreferrer">shadcn/ui</a></strong> - Beautiful component library built on Radix</li></ul><h3 id="state-management-data-handling" tabindex="-1">State Management &amp; Data Handling <a class="header-anchor" href="#state-management-data-handling" aria-label="Permalink to &quot;State Management &amp; Data Handling&quot;">​</a></h3><ul><li><strong><a href="https://github.com/pmndrs/zustand" target="_blank" rel="noreferrer">Zustand</a></strong> - Simple, fast state management</li><li><strong><a href="https://tanstack.com/table" target="_blank" rel="noreferrer">TanStack Table</a></strong> - Powerful table component for data display</li><li><strong><a href="https://react-hook-form.com/" target="_blank" rel="noreferrer">React Hook Form</a></strong> - Performant form handling</li></ul><h3 id="code-editor" tabindex="-1">Code Editor <a class="header-anchor" href="#code-editor" aria-label="Permalink to &quot;Code Editor&quot;">​</a></h3><ul><li><strong><a href="https://microsoft.github.io/monaco-editor/" target="_blank" rel="noreferrer">Monaco Editor</a></strong> - The editor that powers VS Code, providing our SQL editing experience with IntelliSense and syntax highlighting</li></ul><h3 id="icons-visual-elements" tabindex="-1">Icons &amp; Visual Elements <a class="header-anchor" href="#icons-visual-elements" aria-label="Permalink to &quot;Icons &amp; Visual Elements&quot;">​</a></h3><ul><li><strong><a href="https://lucide.dev/" target="_blank" rel="noreferrer">Lucide Icons</a></strong> - Beautiful, consistent icon set</li><li><strong><a href="https://heroicons.com/" target="_blank" rel="noreferrer">Heroicons</a></strong> - Additional UI icons</li></ul><h3 id="build-tools" tabindex="-1">Build Tools <a class="header-anchor" href="#build-tools" aria-label="Permalink to &quot;Build Tools&quot;">​</a></h3><ul><li><strong><a href="https://vitejs.dev/" target="_blank" rel="noreferrer">Vite</a></strong> - Lightning-fast build tool and dev server</li><li><strong><a href="https://bun.sh/" target="_blank" rel="noreferrer">Bun</a></strong> - Fast JavaScript runtime and package manager</li><li><strong><a href="https://www.typescriptlang.org/" target="_blank" rel="noreferrer">TypeScript</a></strong> - Type safety and developer experience</li></ul><h3 id="additional-libraries" tabindex="-1">Additional Libraries <a class="header-anchor" href="#additional-libraries" aria-label="Permalink to &quot;Additional Libraries&quot;">​</a></h3><ul><li><strong><a href="https://date-fns.org/" target="_blank" rel="noreferrer">date-fns</a></strong> - Modern date utility library</li><li><strong><a href="https://zod.dev/" target="_blank" rel="noreferrer">Zod</a></strong> - TypeScript-first schema validation</li><li><strong><a href="https://sonner.emilkowal.ski/" target="_blank" rel="noreferrer">Sonner</a></strong> - Beautiful toast notifications</li><li><strong><a href="https://reactrouter.com/" target="_blank" rel="noreferrer">React Router</a></strong> - Client-side routing</li></ul><h2 id="documentation" tabindex="-1">Documentation <a class="header-anchor" href="#documentation" aria-label="Permalink to &quot;Documentation&quot;">​</a></h2><ul><li><strong><a href="https://vitepress.dev/" target="_blank" rel="noreferrer">VitePress</a></strong> - Fast, simple documentation site generator powering this documentation</li></ul><h2 id="inspiration-community" tabindex="-1">Inspiration &amp; Community <a class="header-anchor" href="#inspiration-community" aria-label="Permalink to &quot;Inspiration &amp; Community&quot;">​</a></h2><p>Thank you to everyone who:</p><ul><li>Reported bugs and issues</li><li>Suggested features and improvements</li><li>Contributed code and documentation</li><li>Shared Duck-UI with others</li><li>Provided feedback and encouragement</li></ul><h2 id="special-thanks" tabindex="-1">Special Thanks <a class="header-anchor" href="#special-thanks" aria-label="Permalink to &quot;Special Thanks&quot;">​</a></h2><h3 id="sponsors" tabindex="-1">Sponsors <a class="header-anchor" href="#sponsors" aria-label="Permalink to &quot;Sponsors&quot;">​</a></h3><p>We&#39;re grateful to our sponsors who support the development of Duck-UI:</p><ul><li><strong><a href="https://www.iberodata.es/" target="_blank" rel="noreferrer">Ibero Data</a></strong> - Data solutions and business intelligence</li><li><strong><a href="https://qxip.net/" target="_blank" rel="noreferrer">QXIP</a></strong> - Next-gen telecom observability</li></ul><p>Interested in sponsoring Duck-UI? <a href="mailto:caio.ricciuti+sponsorship@outlook.com?subject=DUCK-UI%20Sponsorship%20Inquiry" target="_blank" rel="noreferrer">Contact us</a></p><h3 id="contributors" tabindex="-1">Contributors <a class="header-anchor" href="#contributors" aria-label="Permalink to &quot;Contributors&quot;">​</a></h3><p>Thank you to all the contributors who have helped improve Duck-UI:</p><ul><li><a href="https://github.com/ibero-data/duck-ui/graphs/contributors" target="_blank" rel="noreferrer">View all contributors on GitHub</a></li></ul><h2 id="open-source" tabindex="-1">Open Source <a class="header-anchor" href="#open-source" aria-label="Permalink to &quot;Open Source&quot;">​</a></h2><p>Duck-UI is proudly open source and released under the Apache 2.0 License. We believe in the power of open-source software and are committed to contributing back to the community.</p><h2 id="want-to-contribute" tabindex="-1">Want to Contribute? <a class="header-anchor" href="#want-to-contribute" aria-label="Permalink to &quot;Want to Contribute?&quot;">​</a></h2><p>We welcome contributions of all kinds:</p><ul><li>🐛 <strong>Bug Reports</strong>: <a href="https://github.com/ibero-data/duck-ui/issues" target="_blank" rel="noreferrer">Open an issue</a></li><li>💡 <strong>Feature Requests</strong>: <a href="https://github.com/ibero-data/duck-ui/discussions" target="_blank" rel="noreferrer">Start a discussion</a></li><li>📝 <strong>Documentation</strong>: Help improve our docs</li><li>💻 <strong>Code</strong>: Submit a pull request</li><li>⭐ <strong>Support</strong>: Star the project on GitHub</li></ul><p>Every contribution, no matter how small, helps make Duck-UI better for everyone.</p><hr><h2 id="standing-on-the-shoulders-of-giants" tabindex="-1">Standing on the Shoulders of Giants <a class="header-anchor" href="#standing-on-the-shoulders-of-giants" aria-label="Permalink to &quot;Standing on the Shoulders of Giants&quot;">​</a></h2><p>Duck-UI is built using dozens of open-source libraries and tools. While we can&#39;t list every dependency here, we&#39;re deeply grateful to every maintainer and contributor in the JavaScript, React, and DuckDB ecosystems.</p><p><strong>Thank you all! 🙏</strong></p><hr><p><a href="/license.html">View Full License →</a></p>',44)])])}const p=t(n,[["render",i]]);export{g as __pageData,p as default};
